import sys
from collections import Counter

def main():
    S = sys.stdin.readline().strip()
    T = sys.stdin.readline().strip()

    # Count characters in S and T
    count_S = Counter(S)
    count_T = Counter(T)

    # Define the set of characters that can replace '@'
    replaceable = {'a', 't', 'c', 'o', 'd', 'e', 'r'}

    # Calculate the difference between S and T
    diff = Counter()
    for char in count_S:
        diff[char] += count_S[char]
    for char in count_T:
        diff[char] -= count_T[char]

    # Check if the difference can be covered by replacing '@'s
    for char, cnt in diff.items():
        if cnt > 0:
            # Need to replace '@' with this character
            if char in replaceable:
                if count_S['@'] >= cnt:
                    count_S['@'] -= cnt
                else:
                    print("No")
                    return
            else:
                print("No")
                return
        elif cnt < 0:
            # Need to replace '@' with this character in the other string
            char_needed = -cnt
            if char in replaceable:
                if count_T['@'] >= char_needed:
                    count_T['@'] -= char_needed
                else:
                    print("No")
                    return
            else:
                print("No")
                return

    # Check if remaining '@'s can be replaced with any of the allowed characters
    # This is always possible since we can replace them with any of the allowed characters
    print("Yes")

if __name__ == "__main__":
    main()
